and A.WAREKEY = #{warekey}
and A.OWNERKY = #{ownerky}
and upper(A.SKUMKEY) like concat('%', upper(#{skumkey}), '%')
and upper(A.SKUDESC) like concat('%', upper(#{skudesc}), '%')
and upper(A.VENDKEY) like concat('%', upper(#{vendkey}), '%')
and A.SKUSTAT like
#{stat}
