/* updateMskuwc */
update MSKUWC
set
WAREKEY = #{warekey}
, OWNERKY = #{ownerky}
, SKUMKEY = trim(#{skumkey})
, SKUDESC = #{skudesc}
, SKUTYPE = #{skutype}
, CUSKUKY = #{cuskuky}
, CUSKUNM = #{cuskunm}
, VDSKUKY = #{vdskuky}
, VDSKUNM = #{vdskunm}
, SKUSKEY = #{skuskey}
, SKUSDSC = #{skusdsc}
, VENDKEY = #{vendkey}
, PACKKEY = #{packkey}
, TRUNTYP = #{truntyp}
, MINIQTY = #{miniqty}
, SALFQTY = #{salfqty}
, SPUTZON = #{sputzon}
, SPUTLOC = #{sputloc}
, SPIKLOC = #{spikloc}
, VNDFDAY = #{vndfday}
, EANCODE = #{eancode}
, UPCCODE = #{upccode}
, SKUGR01 = #{skugr01}
, SKUGR02 = #{skugr02}
, SKUGR03 = #{skugr03}
, SKUGR04 = #{skugr04}
, SKUGR05 = #{skugr05}
, SKUALT1 = #{skualt1}
, SKUALT2 = #{skualt2}
, SKUALT3 = #{skualt3}
, SKUAT01 = #{skuat01}
, SKUAT02 = #{skuat02}
, SKUAT03 = #{skuat03}
, SKUAT04 = #{skuat04}
, SKUAT05 = #{skuat05}
, SGRWEIG = #{sgrweig}
, SNEWEIG = #{sneweig}
, SKULENG = #{skuleng}
, SKUWIDH = #{skuwidh}
, SKUHEIG = #{skuheig}
, SKUCUBI = #{skucubi}
, SUOMKEY = #{suomkey}
, SKUNOTE = #{skunote}
, SKUWABC = #{skuwabc}
, SKUSTAT = #{skustat}
, LMODATE = DATE_FORMAT(SYSDATE(), '%Y%m%d')
, LMOTIME = DATE_FORMAT(SYSDATE(), '%H%i%s')
, LMOUSER = #{userData.useract}
where COMPKEY = #{compkey}
and UPDTCHK = #{updtchk}


		and WAREKEY = #{oldWarekey}


		and WAREKEY = #{warekey}




		and OWNERKY = #{oldOwnerky}


