		and SKUMKEY = #{oldSkumkey}


		and SKUMKEY = #{skumkey}

mapper.select:
/* selectSkuwcBoxQty */ select MS.SKUMKEY as COMBOVL , concat("(",(ifnull(WS.ABALQTY,0) - ifnull(OA.TSOIQTY,0) - ifnull(WU.UNTRQTY, 0)),")", MS.SKUDESC) as COMBONM , MS.COMPKEY , MS.WAREKEY , MS.OWNERKY , MS.SKUSKEY , MS.VENDKEY , MP.PTNAMLC as VENDNAM , MS.VNDFDAY , MS.MINIQTY from MSKUWC MS inner join MPTNMA MP on MS.COMPKEY = MP.COMPKEY and MS.VENDKEY = MP.PTNRKEY and MP.PTNRTYP = 'VENDER' and MP.PTUSEYN = 'N' left join ( select COMPKEY, WAREKEY, OWNERKY, SKUMKEY, sum((STOTQTY - SBLOQTY) ) as ABALQTY from WSTKKY where COMPKEY = #{userData.compkey} and WAREKEY != 'WHOLESALE' and AREAKEY = 'STG' and STOTQTY - SBLOQTY > 0 and SALLQTY = 0 and SINBQTY = 0 and SOUBQTY = 0 and ZONEKEY != 'TCZZ' group by COMPKEY, WAREKEY, OWNERKY, SKUMKEY ) WS on WS.COMPKEY = MS.COMPKEY and WS.WAREKEY = MS.WAREKEY and WS.OWNERKY = MS.OWNERKY and WS.SKUMKEY = MS.SKUMKEY left join ( select COMPKEY, OWNERKY, SKUMKEY, sum(SOITQTY-RGITQTY) as TSOIQTY from OCOSAL where COMPKEY = #{userData.compkey} and DOCCATE = '200' and DOCTYPE in ('250') and SALSTAT in ('ORDER','ORDFM') and OUBSTAT = 'NEW' and CLOSLYN = 'N' group by COMPKEY, WAREKEY, OWNERKY, SKUMKEY ) OA on OA.COMPKEY = MS.COMPKEY and OA.OWNERKY = MS.OWNERKY and OA.SKUMKEY = MS.SKUMKEY left join ( select COMPKEY, WAREKEY, OWNERKY, SKUMKEY , SUM(case when concat(date_format(SALRQDT, '%Y-%m-%d'),' ', date_format(SALRQTM,'%H-%i-%s') <= date_format(NOW(), '%Y-%m-%d %H:%i:%s')) then SHCUQTY - SHALQTY else RGITQTY- SHALQTY END) as UNTRQTY from WSHPIT where COMPKEY = #{userData.compkey} and WAREKEY != 'WHOLESALE' and SHCUQTY - SHALQTY > 0 and SHPITST != 'F_ALOC' group by COMPKEY, WAREKEY, OWNERKY, SKUMKEY ) WU on WU.COMPKEY = MS.COMPKEY and WU.WAREKEY = MS.WAREKEY and WU.OWNERKY = MS.OWNERKY and WU.SKUMKEY = MS.SKUMKEY where MS.COMPKEY = #{userData.compkey}
and MS.WAREKEY = #{warekey}
and MS.OWNERKY = #{ownerky}
and MS.SKUMKEY in
#{item}
group by MS.COMPKEY, MS.WAREKEY, MS.SKUMKEY, MS.OWNERKY, MS.SKUDESC , MS.SKUSKEY, MS.VENDKEY, MS.VNDFDAY, MS.MINIQTY order by MS.SKUDESC

/* selectSkuwcSelectBox */ select MS.SKUMKEY as COMBOVL , MS.SKUDESC as COMBONM , MS.COMPKEY , MS.WAREKEY , MS.OWNERKY , MS.SKUSKEY , MS.VENDKEY , MS.VNDFDAY , MS.MINIQTY , case when MS.SKUSTAT = 'OUT' then 'N' else 'Y' end as SKUSTAT from MSKUWC MS where MS.COMPKEY = #{userData.compkey}
and MS.WAREKEY = #{warekey}
and MS.OWNERKY = #{ownerky}
and MS.SKUMKEY in
#{item}
and upper(MS.SKUTYPE) = upper(#{skutype})
and upper(MS.SKUTYPE) != #{notSet}
group by MS.COMPKEY, MS.WAREKEY, MS.WAREKEY, MS.SKUMKEY, MS.SKUDESC , MS.OWNERKY, MS.SKUSKEY, MS.VENDKEY, MS.VNDFDAY, MS.MINIQTY order by MS.SKUDESC

/* selectSkuwcBoxCustom */ select MS.COMPKEY as compkey , MS.WAREKEY as warekey , MS.UPCCODE , (select WHNAMLC from MWARMA MW where MW.COMPKEY = MS.COMPKEY and MW.WAREKEY = MS.WAREKEY) as whnamlc , MS.OWNERKY as ownerky , MS.SKUMKEY as skumkey , MS.SKUDESC as skudesc , MS.SKUMKEY as combovl , MS.SKUDESC as combonm , MS.SKUSKEY as skuskey , MS.SUOMKEY as suomkey , MS.MINIQTY as miniqty , MS.PROPQTY as propqty , MS.SALFQTY as salfqty , MP.TRUNTYP as truntyp , case when MS.SKUSTAT = 'OUT' then 'Y' else 'N' end as skustat , MS.PACKKEY as packkey , IFNULL(MP.PACKQTY,0) as packqty , IFNULL(ST.STOTQTY , 0) as stotqty , MS.SKUAT03 , MS.SKUAT01 from MSKUWC MS left join ( select COMPKEY, OWNERKY, WAREKEY , SKUMKEY, SKUDESC , LOTAT17, LOTAT18, LOTAT19, LOTAT20 , (sum(STOTQTY)- sum(SBLOQTY)) as STOTQTY from WSTKKY
COMPKEY = #{userData.compkey}
and WAREKEY = #{warekey}
and AREAKEY = 'STG' and SALLQTY = 0 and SINBQTY = 0 and SOUBQTY = 0
group by COMPKEY, WAREKEY, OWNERKY, SKUMKEY , LOTAT17, LOTAT18, LOTAT19, LOTAT20 ) ST on ST.COMPKEY = MS.COMPKEY and ST.WAREKEY = MS.WAREKEY and ST.OWNERKY = MS.OWNERKY and ST.SKUMKEY = MS.SKUMKEY left join MPAKMA MP on MS.COMPKEY = MP.COMPKEY and MS.WAREKEY = MP.WAREKEY and MS.TRUNTYP = MP.TRUNTYP and MS.PACKKEY = MP.PACKKEY and MP.PKUSEYN = 'Y'
MS.COMPKEY = #{userData.compkey}
and MS.WAREKEY = #{warekey}
and MS.OWNERKY = #{ownerky}
and MS.OWNERKY = #{userData.ownerky}
and MS.SKUSTAT = 'PRODUCT'
group by MS.COMPKEY, MS.WAREKEY, MS.UPCCODE, MS.OWNERKY, MS.SKUMKEY , MS.SKUDESC, MS.SKUSKEY, MS.SUOMKEY, MS.MINIQTY, MS.SALFQTY , MP.TRUNTYP, MS.SKUSTAT, MS.PACKKEY, MP.PACKQTY, ST.STOTQTY , MS.SKUAT03, MS.SKUAT01 order by MS.SKUMKEY

/* selectInboundSkuwcBox */ select MS.SKUMKEY as combovl , MS.SKUDESC as combonm , MS.COMPKEY , MS.SKUSKEY , MS.WAREKEY as WAREKEY , MS.OWNERKY as OWNERKY , case when MS.SKUSTAT = 'OUT' then 'Y' else 'N' end as SKUSTAT , (SELECT SUM( case when (STOTQTY != 0 and SALLQTY = 0 and SINBQTY = 0 and SOUBQTY = 0) then STOTQTY - SBLOQTY else 0 END) as STOTQTY FROM WSTKKY WHERE COMPKEY = MS.COMPKEY AND WAREKEY = MS.WAREKEY AND AREAKEY = 'STG' AND OWNERKY = MS.OWNERKY AND SKUMKEY = MS.SKUMKEY ) AS STOTQTY , IFNULL(MS.SUOMKEY, NULL) AS SUOMKEY , MS.PACKKEY as PACKKEY , MS.TRUNTYP as TRUNTYP from MSKUWC MS
and MS.COMPKEY = #{userData.compkey}
and MS.WAREKEY = #{warekey}
and MS.OWNERKY = #{ownerky}
and MS.SKUMKEY in
#{item}
order by MS.SKUDESC

/* selectSkuwcOms2SB */ select MS.SKUMKEY as COMBOVL , MS.SKUDESC , MS.SKUSKEY , IFNULL(OD.SEDPRIC, 0) as SEDPRIC , IFNULL(OA.TSOIQTY, 0) as TSOIQTY , IFNULL(WS.ABALQTY, 0) as ABALQTY , IFNULL(WH.WBALQTY, 0) as WBALQTY from MSKUWC MS left join OCOIDC OD on OD.COMPKEY = MS.COMPKEY and OD.OWNERKY = MS.OWNERKY and OD.SKUMKEY = MS.SKUMKEY
and OD.RETAKEY = #{retakey}
left join ( select COMPKEY, OWNERKY, SKUMKEY , sum(case when PAYTYPE = 'RECEIPT' then SOITQTY else 0 end) as RECEQTY , sum(case when PAYTYPE = 'BILLING' then SOITQTY else 0 end) as BILLQTY , sum(SOITQTY) as TSOIQTY from OCOSAL where COMPKEY = #{userData.compkey} and SALSTAT in ('ORDER','ORDFM') and OUBSTAT = 'NEW' and CLOSLYN = 'N' group by COMPKEY, OWNERKY, SKUMKEY ) OA on OA.COMPKEY = MS.COMPKEY and OA.OWNERKY = MS.OWNERKY and OA.SKUMKEY = MS.SKUMKEY left join ( select COMPKEY, WAREKEY, OWNERKY, SKUMKEY, sum((STOTQTY - SBLOQTY)) as ABALQTY from WSTKKY where COMPKEY = #{userData.compkey} and AREAKEY = 'STG' and STOTQTY - SBLOQTY > 0 and SALLQTY = 0 and SINBQTY = 0 and SOUBQTY = 0 group by COMPKEY, WAREKEY, OWNERKY, SKUMKEY ) WS on WS.COMPKEY = MS.COMPKEY and WS.WAREKEY = MS.WAREKEY and WS.OWNERKY = MS.OWNERKY and WS.SKUMKEY = MS.SKUMKEY left join ( select COMPKEY, LOCAKEY, OWNERKY, SKUMKEY, sum((STOTQTY - SBLOQTY)) as WBALQTY from WSTKKY where COMPKEY = #{userData.compkey} and WAREKEY = 'WHOLESALE' and AREAKEY = 'STG' and STKSTAT = '80' and STOTQTY - SBLOQTY > 0 and SALLQTY = 0 and SINBQTY = 0 and SOUBQTY = 0 group by COMPKEY, LOCAKEY, OWNERKY, SKUMKEY ) WH on WH.COMPKEY = MS.COMPKEY and WH.LOCAKEY = #{brandcd} and WH.OWNERKY = MS.OWNERKY and WH.SKUMKEY = MS.SKUMKEY where MS.COMPKEY = #{userData.compkey} and MS.OWNERKY = #{ownerky} and MS.WAREKEY = #{warekey}
and MS.SKUMKEY in
#{item}
order by MS.SKUDESC

/* selectSkuwcOms2SB */ select MS.SKUMKEY as COMBOVL , CONCAT("(", IFNULL(SK.TOTQTY,0),") ", MS.SKUDESC) as COMBONM , IFNULL(SK.TOTQTY,0) as STOTQTY , MS.OWNERKY , MS.SKUSKEY , MS.VENDKEY , MP.PTNAMLC as VENDNAM , MS.VNDFDAY , MS.MINIQTY from MSKUWC MS left join ( select COMPKEY, OWNERKY, WAREKEY, SKUMKEY, SKUDESC, (sum(STOTQTY)- sum(SBLOQTY)) as TOTQTY from WSTKKY where COMPKEY = #{userData.compkey}
and WAREKEY = #{warekey}
and OWNERKY = #{ownerky}
and STKSTAT = #{stkstat}
and SKUMKEY in
#{item}
and AREAKEY = 'STG' and ZONEKEY not in ( 'TCZZ' ) and SALLQTY = 0 and SINBQTY = 0 and SOUBQTY = 0 group by SKUMKEY ) SK on MS.COMPKEY = SK.COMPKEY and MS.OWNERKY = SK.OWNERKY and MS.SKUMKEY = SK.SKUMKEY inner join MPTNMA MP on MS.COMPKEY = MP.COMPKEY and MS.VENDKEY = MP.PTNRKEY and MP.PTNRTYP = 'VENDER' and MP.PTUSEYN = 'N' where MS.COMPKEY = #{userData.compkey}
and MS.WAREKEY = #{warekey}
and MS.OWNERKY = #{ownerky}
and MS.SKUMKEY in
#{item}
group by MS.OWNERKY, MS.SKUMKEY, MS.SKUSKEY, MS.SKUDESC, SK.TOTQTY , MS.VENDKEY, MP.PTNAMLC, MS.VNDFDAY, MS.MINIQTY order by MS.SKUDESC

/* selectSkwucBoxByWarekey */
select MS.SKUMKEY as COMBOVL
, MS.SKUDESC as COMBONM
from MSKUWC MS
where MS.COMPKEY = #{userData.compkey}

	and MS.WAREKEY = #{warekey}


	and MS.OWNERKY = #{ownerky}


	and MS.SKUMKEY = #{skumkey}

group by MS.SKUMKEY, MS.SKUDESC
order by MS.SKUDESC

/*selectMskuwcForSkustat*/
select COMPKEY, WAREKEY, OWNERKY, SKUMKEY, SKUSTAT
from MSKUWC
where COMPKEY = #{userData.compkey}

	and WAREKEY = #{warekey}

order by COMPKEY, WAREKEY, OWNERKY, SKUMKEY

/* selectMuomma */ select concat(COMPKEY, UOMEKEY) as ROWKEY , COMPKEY, UOMEKEY, UOMENAM, UOUSEYN , FN_COM_TODATE(CREDATE) as CREDATE, FN_COM_TOTIME(CRETIME) as CRETIME, fn_sy_usernam(COMPKEY, CREUSER) as CREUSER , FN_COM_TODATE(LMODATE) as LMODATE, FN_COM_TOTIME(LMOTIME) as LMOTIME, fn_sy_usernam(COMPKEY, LMOUSER) as LMOUSER , INDIBZL, INDIARC, UPDTCHK from MUOMMA where COMPKEY = #{userData.compkey}
and upper(UOMEKEY) like concat('%', upper(#{uomekey}), '%')
and upper(UOMENAM) like concat('%', upper(#{uomenam}), '%')
and UOUSEYN = #{uouseyn}
order by COMPKEY, UOMEKEY

