order by UOMEKEY, UOMENAM

/* selectMtutmaList */ select concat(COMPKEY, TRUNTYP) as ROWKEY , COMPKEY, TRUNTYP, TRUNNAM, TRUSEYN, TUTLENG , TUTWIDH, TUTHEIG, TUTCUBI, TUTWEIG, UOMEKEY , FN_COM_TODATE(CREDATE) as CREDATE, FN_COM_TOTIME(CRETIME) as CRETIME, fn_sy_usernam(COMPKEY, CREUSER) as CREUSER , FN_COM_TODATE(LMODATE) as LMODATE, FN_COM_TOTIME(LMOTIME) as LMOTIME, fn_sy_usernam(COMPKEY, LMOUSER) as LMOUSER , INDIBZL, INDIARC, UPDTCHK from MTUTMA where COMPKEY = #{userData.compkey}
