select TRUNTYP as COMBOVL
, TRUNNAM as COMBONM
from MTUTMA
where COMPKEY = #{userData.compkey}


		and TRUSEYN = #{truseyn}


		and TRUSEYN = 'Y'


group by TRUNTYP, TRUNNAM
order by TRUNTYP, TRUNNAM

/* selectMpakmaList */
select concat(COMPKEY, WAREKEY, PACKKEY, TRUNTYP) as ROWKEY
, COMPKEY, WAREKEY, PACKKEY, TRUNTYP, PKUSEYN, PACKQTY, PUOMKEY
, FN_COM_TODATE(CREDATE) as CREDATE, FN_COM_TOTIME(CRETIME) as CRETIME, fn_sy_usernam(COMPKEY, CREUSER) as CREUSER
, FN_COM_TODATE(LMODATE) as LMODATE, FN_COM_TOTIME(LMOTIME) as LMOTIME, fn_sy_usernam(COMPKEY, LMOUSER) as LMOUSER
, INDIBZL, INDIARC, UPDTCHK
from MPAKMA
where COMPKEY = #{userData.compkey}

	and WAREKEY = #{warekey}


	and PACKKEY = #{packkey}


	and TRUNTYP = #{truntyp}



		and PKUSEYN = #{pkuseyn}


		and PKUSEYN = 'Y'


order by COMPKEY, WAREKEY, PACKKEY, TRUNTYP

mapper.insert:
/* insertMpakma */
insert
into MPAKMA( COMPKEY, WAREKEY, PACKKEY, TRUNTYP, PKUSEYN, PACKQTY, PUOMKEY
, CREDATE, CRETIME, CREUSER, LMODATE, LMOTIME, LMOUSER )
values
( #{compkey}, #{warekey}, #{packkey}, #{truntyp}, #{pkuseyn}, #{packqty}, #{puomkey}
, to_char(now(),'YYYYMMDD'), to_char(now(),'hh24miss'), #{userData.useract}
, to_char(now(),'YYYYMMDD'), to_char(now(),'hh24miss'), #{userData.useract} )

mapper.update:
/* updateMpakma */
update MPAKMA
set WAREKEY = #{warekey}
, PACKKEY = #{packkey}
, TRUNTYP = #{truntyp}
, PKUSEYN = #{pkuseyn}
, PACKQTY = #{packqty}
, PUOMKEY = #{puomkey}
, LMODATE = to_char(now(),'YYYYMMDD')
, LMOTIME = to_char(now(),'hh24miss')
, LMOUSER = #{userData.useract}
where COMPKEY = #{compkey}
and UPDTCHK = #{updtchk}


		and WAREKEY = #{oldWarekey}


		and WAREKEY = #{warekey}




		and PACKKEY = #{oldPackkey}


		and PACKKEY = #{packkey}




		and TRUNTYP = #{oldTruntyp}


		and TRUNTYP = #{truntyp}

mapper.select:
/* selectMpakmaBox */
select A.TRUNTYP as COMBOVL
, B.TRUNNAM as COMBONM
from MPAKMA A
inner join MTUTMA B
on A.COMPKEY = B.COMPKEY
and A.TRUNTYP = B.TRUNTYP
where A.COMPKEY = #{userData.compkey}

	and A.WAREKEY = #{warekey}


	and A.PACKKEY = #{packkey}



		and A.PKUSEYN = #{pkuseyn}


		and A.PKUSEYN = 'Y'


group by A.TRUNTYP, B.TRUNNAM
order by A.TRUNTYP, B.TRUNNAM

/* selectMpakmaPackBox */
select A.TRUNTYP as COMBOVL
, A.PACKKEY as COMBONM
from MPAKMA A
where A.COMPKEY = #{userData.compkey}

	and A.WAREKEY = #{warekey}


	and A.TRUNTYP = #{truntyp}


	and A.PACKKEY = #{packkey}



		and A.PKUSEYN = #{pkuseyn}


		and A.PKUSEYN = 'Y'


group by A.TRUNTYP, A.PACKKEY
order by A.PACKKEY

/* selectMskuwcSetList */
select
concat(WC.COMPKEY, WC.WAREKEY, WC.OWNERKY, WC.SKUMKEY) as ROWKEY
, WC.COMPKEY, WC.WAREKEY, WC.OWNERKY, WC.SKUMKEY as SKUMKEY
, WC.SKUDESC as SKUDESC
, FN_COM_TODATE(WC.CREDATE) as CREDATE, FN_COM_TOTIME(WC.CRETIME) as CRETIME, fn_sy_usernam(WC.COMPKEY, WC.CREUSER) as CREUSER
, FN_COM_TODATE(WC.LMODATE) as LMODATE, FN_COM_TOTIME(WC.LMOTIME) as LMOTIME, fn_sy_usernam(WC.COMPKEY, WC.LMOUSER) as LMOUSER
, WC.UPDTCHK
from MSKUWC WC
where WC.COMPKEY = #{userData.compkey}
and WC.WAREKEY = #{warekey}

	and WC.OWNERKY = #{ownerky}


	and upper(WC.SKUMKEY) like concat('%',upper(#{skumkey}),'%')


	and upper(WC.SKUDESC) like concat('%',upper(#{skudesc}),'%')

and WC.SKUTYPE = 'SET'

	and WC.SKUMKEY in (
		select SKUMKEY
		from MSKUST
			where (COMPKEY, WAREKEY, OWNERKY, SBSKUKY) in (
				(
					select COMPKEY, WAREKEY, OWNERKY, SKUMKEY
					from MSKUWC
					where COMPKEY = #{userData.compkey}

						and OWNERKY = #{ownerky}

					and WAREKEY = #{warekey}
					and SKUTYPE = 'KMAT'

						and upper(SKUMKEY) like concat('%', upper(#{sbskuky}),'%')


						and upper(SKUDESC) like concat('%', upper(#{sbskuds}),'%')

				)
		)
	)

order by WC.COMPKEY, WC.WAREKEY, WC.OWNERKY, WC.SKUMKEY

