update MSKUWC
set
WAREKEY = #{warekey}
, OWNERKY = #{ownerky}
, SKUMKEY = #{skumkey}
, SKUDESC = #{skudesc}
, SKUTYPE = 'SET'
, LMODATE = DATE_FORMAT(SYSDATE(), '%Y%m%d')
, LMOTIME = DATE_FORMAT(SYSDATE(), '%H%i%s')
, LMOUSER = #{userData.useract}
where COMPKEY = #{compkey}
and UPDTCHK = #{updtchk}


		and SKUMKEY = #{oldSkumkey}


		and SKUMKEY = #{skumkey}




		and SKUDESC = #{oldSkudesc}


		and SKUDESC = #{skudesc}

